<?php namespace App\Models\Domain; class Contact extends BaseModel { public int $id; public string $name; public string $email; public string $subject; public string $message; public string $status; public string $createdAt; public static function fromArray(array $data): static { $obj = new static(); $obj->id = (int) $data['id']; $obj->name = $data['name']; $obj->email = $data['email']; $obj->subject = $data['subject']; $obj->message = $data['message']; $obj->status = $data['status']; $obj->createdAt = $data['created_at']; return $obj; } }
